def _align_rasters(left: Raster, right: Raster) -> tuple[Raster, Raster]:
    if left.width == right.width and left.height == right.height:
        return left.to_rgb(), right.to_rgb()
    target_width = min(left.width, right.width)
    target_height = min(left.height, right.height)
    return (
        resize_rgb(left.to_rgb(), target_width, target_height),
        resize_rgb(right.to_rgb(), target_width, target_height),
    )

