def _channel_stats(left: Raster, right: Raster, channel: int) -> dict[str, float]:
    left_rgb = left.to_rgb()
    right_rgb = right.to_rgb()
    differences: list[float] = []
    for index in range(left_rgb.width * left_rgb.height):
        offset = index * 3 + channel
        differences.append(abs(left_rgb.data[offset] - right_rgb.data[offset]))
    if not differences:
        return {"mae": 0.0, "max_delta": 0.0}
    return {
        "mae": round(sum(differences) / len(differences), 3),
        "max_delta": round(max(differences), 3),
    }

