def _mse(left: Raster, right: Raster) -> float:
    left_rgb, right_rgb = _align_rasters(left, right)
    pixel_count = left_rgb.width * left_rgb.height
    if pixel_count == 0:
        return 0.0
    total = 0.0
    for index in range(0, len(left_rgb.data), 3):
        for channel in range(3):
            delta = left_rgb.data[index + channel] - right_rgb.data[index + channel]
            total += delta * delta
    return total / (pixel_count * 3)

