def _size_delta_percent(left: Raster, right: Raster) -> float:
    left_pixels = left.width * left.height
    right_pixels = right.width * right.height
    if left_pixels == 0:
        return 0.0
    return round(((right_pixels - left_pixels) / left_pixels) * 100, 2)

