def _pixel_agreement_percent(left: Raster, right: Raster, tolerance: int = 2) -> float:
    left_rgb, right_rgb = _align_rasters(left, right)
    pixel_count = left_rgb.width * left_rgb.height
    if pixel_count == 0:
        return 100.0
    matches = 0
    for index in range(0, len(left_rgb.data), 3):
        if all(
            abs(left_rgb.data[index + channel] - right_rgb.data[index + channel]) <= tolerance
            for channel in range(3)
        ):
            matches += 1
    return round((matches / pixel_count) * 100, 2)

