def _quality_label(psnr: float | None, ssim: float) -> str:
    if ssim >= 0.98 and (psnr is None or psnr >= 40):
        return "excellent"
    if ssim >= 0.92 and (psnr is None or psnr >= 30):
        return "good"
    if ssim >= 0.80 and (psnr is None or psnr >= 22):
        return "fair"
    return "poor"
